def hashcode(n: int) -> str:
    return hashlib.sha256(str(n).encode('utf-8')).hexdigest()

@pytest.mark.parametrize("d1, d2, result, testcase", q4_testcases)
def test_q4(d1, d2, result, testcase):
    d3 = dictFormatting(merge_value(d1, d2))
    if testcase == True:
        assert d3 == result
    else:
        assert hashcode(d3) == result